def alien_order(words):
    import heapq

    chars = set()
    for w in words:
        chars.update(w)

    adj = {c: set() for c in chars}
    indegree = {c: 0 for c in chars}

    for w1, w2 in zip(words, words[1:]):
        min_len = min(len(w1), len(w2))
        found_diff = False
        for i in range(min_len):
            if w1[i] != w2[i]:
                if w2[i] not in adj[w1[i]]:
                    adj[w1[i]].add(w2[i])
                    indegree[w2[i]] += 1
                found_diff = True
                break
        if not found_diff and len(w1) > len(w2):
            return ""

    heap = [c for c in chars if indegree[c] == 0]
    heapq.heapify(heap)
    order = []
    while heap:
        c = heapq.heappop(heap)
        order.append(c)
        for nxt in adj[c]:
            indegree[nxt] -= 1
            if indegree[nxt] == 0:
                heapq.heappush(heap, nxt)

    if len(order) != len(chars):
        return ""
    return "".join(order)
